<template>
  <div class="login-bg">
    <div class="login-modal" :class="{ show: mounted }">
      <template v-if="!userType">
        <h2>Вход в кабинет</h2>
        <div class="user-type-select">
          <button @click="selectType('factory')" class="user-type-btn">
            🏭 Производитель
          </button>
          <button @click="selectType('supplier')" class="user-type-btn">
            🛠️ Поставщик услуг
          </button>
        </div>
      </template>
      <template v-else>
        <h2>
          Вход для
          <span v-if="userType === 'factory'">производителей</span>
          <span v-else>поставщиков услуг</span>
        </h2>
        <form @submit.prevent="login" autocomplete="off">
          <div class="input-group">
            <span class="input-icon">👤</span>
            <input v-model="username" type="text" placeholder="Логин" required />
          </div>
          <div class="input-group">
            <span class="input-icon">🔒</span>
            <input v-model="password" type="password" placeholder="Пароль" required />
          </div>
          <button type="submit">Войти</button>
          <button type="button" class="back-btn" @click="userType = ''">Назад</button>
          <transition name="fade">
            <div v-if="error" class="error">{{ error }}</div>
          </transition>
        </form>
      </template>
    </div>
  </div>
</template>

<script setup>
import { ref, onMounted } from 'vue'
import { useRouter } from 'vue-router'

const router = useRouter()
const username = ref('')
const password = ref('')
const error = ref('')
const mounted = ref(false)
const userType = ref('')

onMounted(() => {
  mounted.value = true
  if (localStorage.getItem('isFactoryLoggedIn') === 'true') {
    router.push('/factory-cabinet')
  }
  if (localStorage.getItem('isSupplierLoggedIn') === 'true') {
    router.push('/for-service-providers')
  }
})

function selectType(type) {
  userType.value = type
}

function login() {
  if (userType.value === 'factory') {
    if (username.value === '1111' && password.value === '1111') {
      localStorage.setItem('isFactoryLoggedIn', 'true')
      router.push('/factory-cabinet')
      return
    }
  }
  if (userType.value === 'supplier') {
    if (username.value === '2222' && password.value === '2222') {
      localStorage.setItem('isSupplierLoggedIn', 'true')
      router.push('/supplier-cabinet')
      return
    }
  }
  error.value = 'Неверный логин или пароль'
  setTimeout(() => (error.value = ''), 2500)
}
</script>

<style scoped>
.login-bg {
  min-height: 100vh;
  background: linear-gradient(120deg, #e0f7fa 0%, #fce4ec 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 8px;
}
.login-modal {
  background: #fff;
  border-radius: 18px;
  box-shadow: 0 8px 32px rgba(44,62,80,0.13), 0 2px 8px rgba(44,62,80,0.08);
  padding: 2.2rem 2rem 2rem 2rem;
  max-width: 350px;
  width: 100%;
  text-align: center;
  opacity: 0;
  transform: translateY(30px) scale(0.98);
  transition: all 0.5s cubic-bezier(.4,2,.3,1);
}
.login-modal.show {
  opacity: 1;
  transform: translateY(0) scale(1);
}
h2 {
  font-family: 'Montserrat', Arial, sans-serif;
  font-size: 1.5rem;
  font-weight: 800;
  letter-spacing: 1px;
  margin-bottom: 1.5rem;
  background: linear-gradient(90deg, #e73292 0%, #62f5df 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.user-type-select {
  display: flex;
  flex-direction: column;
  gap: 1.2rem;
  margin-bottom: 1.2rem;
}
.user-type-btn {
  background: linear-gradient(90deg, #00cfff 0%, #e73292 100%);
  color: #fff;
  border: none;
  padding: 0.9rem 0;
  border-radius: 10px;
  font-weight: 700;
  font-size: 1.08rem;
  cursor: pointer;
  width: 100%;
  box-shadow: 0 2px 8px rgba(0,207,255,0.08);
  transition: background 0.18s, transform 0.15s;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.7rem;
}
.user-type-btn:hover {
  background: linear-gradient(90deg, #009bb3 0%, #e73292 100%);
  transform: translateY(-2px) scale(1.03);
}

form {
  display: flex;
  flex-direction: column;
  gap: 1.1rem;
}
.input-group {
  position: relative;
  display: flex;
  align-items: center;
}
.input-icon {
  position: absolute;
  left: 12px;
  font-size: 1.1rem;
  opacity: 0.7;
  pointer-events: none;
}
input {
  width: 100%;
  padding: 0.7rem 0.7rem 0.7rem 2.2rem;
  border-radius: 8px;
  border: 1.5px solid #e0e0e0;
  font-size: 1rem;
  background: #fafdff;
  transition: border 0.18s;
}
input:focus {
  border: 1.5px solid #00cfff;
  outline: none;
  background: #fff;
}
button {
  background: linear-gradient(90deg, #00cfff 0%, #e73292 100%);
  color: #fff;
  border: none;
  padding: 0.8rem 0;
  border-radius: 10px;
  font-weight: 700;
  font-size: 1.08rem;
  cursor: pointer;
  width: 100%;
  box-shadow: 0 2px 8px rgba(0,207,255,0.08);
  transition: background 0.18s, transform 0.15s;
}
button:hover {
  background: linear-gradient(90deg, #009bb3 0%, #e73292 100%);
  transform: translateY(-2px) scale(1.03);
}
.back-btn {
  background: #fafdff;
  color: #00cfff;
  border: 1.5px solid #00cfff;
  margin-top: 0.5rem;
  font-weight: 600;
  font-size: 1rem;
  border-radius: 8px;
  transition: background 0.15s, color 0.15s;
}
.back-btn:hover {
  background: #00cfff;
  color: #fff;
}

.error {
  color: #fff;
  background: #e74c3c;
  border-radius: 8px;
  padding: 0.6rem 0.5rem;
  margin-top: 0.5rem;
  font-size: 0.98rem;
  box-shadow: 0 2px 8px #e74c3c22;
  animation: shake 0.3s;
}
@keyframes shake {
  10%, 90% { transform: translateX(-2px); }
  20%, 80% { transform: translateX(4px); }
  30%, 50%, 70% { transform: translateX(-6px); }
  40%, 60% { transform: translateX(6px); }
}

.fade-enter-active, .fade-leave-active {
  transition: opacity 0.3s;
}
.fade-enter-from, .fade-leave-to {
  opacity: 0;
}

/* Мобильная адаптация */
@media (max-width: 500px) {
  .login-modal {
    padding: 1.2rem 0.5rem 1.2rem 0.5rem;
    max-width: 98vw;
    border-radius: 12px;
  }
  h2 {
    font-size: 1.08rem;
    margin-bottom: 1rem;
  }
  input {
    font-size: 0.98rem;
    padding: 0.6rem 0.6rem 0.6rem 2rem;
  }
  button, .user-type-btn, .back-btn {
    font-size: 1rem;
    padding: 0.7rem 0;
  }
}
</style>