<template>
  <section class="service-hero">
    <h1 class="service-title">Маркетплейс услуг</h1>
    <div class="service-controls">
      <input
          v-model="search"
          class="service-search"
          type="text"
          placeholder="Поиск по услугам..."
      />
      <div class="service-categories">
        <button
            v-for="cat in categories"
            :key="cat"
            :class="['service-category', { active: selectedCategory === cat }]"
            @click="selectCategory(cat)"
        >
          {{ cat }}
        </button>
      </div>
    </div>
    <div class="service-list">
      <div
          v-for="service in filteredServices"
          :key="service.id"
          class="service-card"
      >
        <img :src="service.image" :alt="service.name" class="service-img" />
        <h2 class="service-name">{{ service.name }}</h2>
        <p class="service-desc">{{ service.desc }}</p>
        <div class="service-card-actions">
          <button class="service-btn add" @click="addToCart(service)">В корзину</button>
          <router-link :to="`/services/${service.id}`" class="service-btn details">Подробнее</router-link>
        </div>
      </div>
    </div>
    <transition name="fade">
      <div v-if="showToast" class="service-toast">
        Услуга добавлена в корзину!
      </div>
    </transition>
  </section>
</template>

<script setup>
import { ref, computed } from 'vue'

const categories = ['Все', 'Ремонт БПЛА', 'Аренда дронов', 'Аэрофотосъёмка']

const services = ref([
  {
    id: 1,
    name: 'Ремонт квадрокоптеров',
    desc: 'Профессиональный ремонт и настройка дронов всех моделей.',
    image: 'https://cdn-icons-png.flaticon.com/512/2933/2933887.png',
    category: 'Ремонт БПЛА'
  },
  {
    id: 2,
    name: 'Замена аккумуляторов',
    desc: 'Быстрая замена и подбор аккумуляторов для БПЛА.',
    image: 'https://cdn-icons-png.flaticon.com/512/1048/1048953.png',
    category: 'Ремонт БПЛА'
  },
  {
    id: 3,
    name: 'Диагностика электроники',
    desc: 'Комплексная диагностика и устранение неисправностей.',
    image: 'https://cdn-icons-png.flaticon.com/512/1048/1048952.png',
    category: 'Ремонт БПЛА'
  },
  {
    id: 4,
    name: 'Аренда квадрокоптера',
    desc: 'Прокат современных дронов для съёмок и мониторинга.',
    image: 'https://cdn-icons-png.flaticon.com/512/2933/2933887.png',
    category: 'Аренда дронов'
  },
  {
    id: 5,
    name: 'Аренда FPV-дрона',
    desc: 'Аренда FPV-дронов для гонок и развлечений.',
    image: 'https://cdn-icons-png.flaticon.com/512/1048/1048952.png',
    category: 'Аренда дронов'
  },
  {
    id: 6,
    name: 'Аэрофотосъёмка недвижимости',
    desc: 'Профессиональная съёмка объектов недвижимости с воздуха.',
    image: 'https://cdn-icons-png.flaticon.com/512/1048/1048953.png',
    category: 'Аэрофотосъёмка'
  },
  {
    id: 7,
    name: 'Аэрофотосъёмка мероприятий',
    desc: 'Съёмка свадеб, праздников и событий с дрона.',
    image: 'https://cdn-icons-png.flaticon.com/512/2933/2933887.png',
    category: 'Аэрофотосъёмка'
  },
  {
    id: 8,
    name: 'Монтаж видео с дрона',
    desc: 'Профессиональный монтаж и обработка видео, снятого с дрона.',
    image: 'https://cdn-icons-png.flaticon.com/512/1048/1048952.png',
    category: 'Аэрофотосъёмка'
  }
])

const search = ref('')
const selectedCategory = ref('Все')
const showToast = ref(false)

const filteredServices = computed(() => {
  let result = services.value
  if (selectedCategory.value && selectedCategory.value !== 'Все') {
    result = result.filter(service => service.category === selectedCategory.value)
  }
  if (search.value.trim()) {
    const q = search.value.trim().toLowerCase()
    result = result.filter(service => service.name.toLowerCase().includes(q))
  }
  return result
})

function selectCategory(cat) {
  selectedCategory.value = cat
}

function addToCart(service) {
  let cart = JSON.parse(localStorage.getItem('cart') || '[]')
  cart.push(service)
  localStorage.setItem('cart', JSON.stringify(cart))
  showToast.value = true
  setTimeout(() => (showToast.value = false), 1500)
}
</script>

