<template>
  <div class="service-cabinet">
    <button
        class="logout-btn"
        @click="logout"
        :style="{ opacity: logoutBtnOpacity, transition: 'opacity 0.3s' }"
    >
      Выйти
    </button>
    <div class="cabinet-header">
      <span class="cabinet-header-icon">
        <img src="https://img.icons8.com/color/48/000000/services.png" alt="icon" />
      </span>
      <div>
        <h2>Личный кабинет поставщика услуг</h2>
        <p>Здесь вы можете управлять информацией о вашей компании и добавлять новые услуги для клиентов.</p>
      </div>
    </div>
    <div class="cabinet-main">
      <div class="cabinet-left">
        <div class="provider-card">
          <h3>{{ provider.name }}</h3>
          <p><b>Страна:</b> {{ provider.country }}</p>
          <p><b>Специализация:</b> {{ provider.specialty }}</p>
          <p><b>Год основания:</b> {{ provider.founded }}</p>
          <p class="provider-desc">{{ provider.desc }}</p>
        </div>
      </div>
      <div class="cabinet-right">
        <div class="add-services-row">
          <div class="add-service-block">
            <h4>Добавить услугу</h4>
            <form @submit.prevent="addService">
              <input v-model="newService.name" placeholder="Название услуги" required />
              <input v-model="newService.image" placeholder="Ссылка на изображение" required />
              <textarea v-model="newService.desc" placeholder="Описание услуги" required></textarea>
              <button type="submit">Добавить</button>
            </form>
          </div>
          <div class="added-services-block">
            <h5>Добавленные услуги:</h5>
            <div v-if="services.length">
              <div v-for="(service, idx) in services" :key="idx" class="service-item">
                <img :src="service.image" :alt="service.name" />
                <div>
                  <b>{{ service.name }}</b>
                  <div>{{ service.desc }}</div>
                </div>
              </div>
            </div>
            <div v-else class="no-services">
              <span style="font-size:2rem;">🛎️</span>
              <div>Пока нет добавленных услуг.<br>Добавьте первую услугу!</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
const providers = [
  {
    name: 'ООО "СервисПрофи"',
    country: 'Россия',
    specialty: 'Техническое обслуживание БПЛА',
    founded: 2015,
    desc: 'Профессиональное обслуживание и ремонт беспилотных летательных аппаратов. Работаем с корпоративными и частными клиентами.'
  },
  {
    name: 'DroneConsult GmbH',
    country: 'Германия',
    specialty: 'Консалтинг и обучение',
    founded: 2010,
    desc: 'Обучение пилотов, консультации по внедрению дронов в бизнес-процессы, аудит и сопровождение проектов.'
  },
  {
    name: 'AeroLogistics',
    country: 'Китай',
    specialty: 'Логистика и доставка',
    founded: 2018,
    desc: 'Организация доставки грузов с помощью дронов, логистические решения для e-commerce и промышленности.'
  }
]

export default {
  name: 'SupplierCabinet',
  data() {
    return {
      provider: providers[Math.floor(Math.random() * providers.length)],
      newService: { name: '', image: '', desc: '' },
      services: [],
      logoutBtnOpacity: 1
    }
  },
  created() {
    if (localStorage.getItem('isSupplierLoggedIn') !== 'true') {
      this.$router.push('/for-service-providers');
    }
  },
  mounted() {
    window.addEventListener('scroll', this.handleScroll);
  },
  beforeUnmount() {
    window.removeEventListener('scroll', this.handleScroll);
  },
  methods: {
    logout() {
      localStorage.removeItem('isSupplierLoggedIn');
      this.$router.push('/for-manufacturers');
    },
    addService() {
      this.services.push({ ...this.newService });
      this.newService = { name: '', image: '',desc: '' };
    },
    handleScroll() {
      if (window.innerWidth <= 600) {
        const currentScroll = window.scrollY;
        this.logoutBtnOpacity = Math.max(1 - currentScroll / 120, 0.2);
      } else {
        this.logoutBtnOpacity = 1;
      }
    }
  }
}
</script>

